    public static DataTable GetTable(string table, string search = "") { if (!IsAllowedTable(table)) throw new ArgumentException("Invalid table: " + table); if (table == "Products" || table == "OrderItems") try { EnsureProductImagePathColumn(); } catch { } return table switch { "Orders" => Sql(OrdersSql(search), search), "OrderItems" => Sql(OrderItemsSql(search), search), "SupplierItems" => Sql(SupplierItemsSql(search), search), "PurchaseOrders" => Sql(PurchaseOrdersSql(search), search), "Complaints" => Sql(ComplaintsSql(search), search), "Stock" => Sql(StockSql(search), search), "StockMovements" => Sql(StockMovementsSql(search), search), "ReplySlips" => Sql(ReplySlipsSql(search), search), _ => Basic(table, search) }; }
    static DataTable Basic(string t, string s) { var dt = new DataTable(); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); if (string.IsNullOrWhiteSpace(s)) cmd.CommandText = $"SELECT * FROM `{t}` ORDER BY Id DESC"; else { cmd.CommandText = $"SELECT * FROM `{t}` WHERE " + string.Join(" OR ", Cols[t].Select(x => $"CAST(`{x}` AS CHAR) LIKE @s")) + " ORDER BY Id DESC"; cmd.Parameters.AddWithValue("@s", "%" + s.Trim() + "%"); } using var r = cmd.ExecuteReader(); dt.Load(r); return dt; }
    static DataTable Sql(string sql, string s = "") { var dt = new DataTable(); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = sql; if (!string.IsNullOrWhiteSpace(s)) cmd.Parameters.AddWithValue("@s", "%" + s.Trim() + "%"); using var r = cmd.ExecuteReader(); dt.Load(r); return dt; }
    static string OrdersSql(string s) => "SELECT o.Id,o.OrderNo,c.CustomerName,p.ProductCode,p.ProductName,o.Quantity,o.Status,o.OrderDate,o.Priority,u.Username SalesUser,o.TotalAmount,o.CustomerId,o.ProductId,o.SalesUserId FROM Orders o JOIN Customers c ON o.CustomerId=c.Id JOIN Products p ON o.ProductId=p.Id LEFT JOIN Users u ON o.SalesUserId=u.Id" + (string.IsNullOrWhiteSpace(s) ? "" : " WHERE o.OrderNo LIKE @s OR c.CustomerName LIKE @s OR p.ProductCode LIKE @s OR p.ProductName LIKE @s OR o.Status LIKE @s OR o.Priority LIKE @s OR u.Username LIKE @s") + " ORDER BY o.Id DESC";
    static string OrderItemsSql(string s) => "SELECT oi.Id,o.Id AS SalesOrderId,o.OrderNo,c.CustomerName,p.ProductCode,p.ProductName,p.ImagePath,oi.Description,oi.Quantity,oi.UnitPrice,oi.Discount,oi.LineTotal,oi.OrderId,oi.ProductId FROM OrderItems oi JOIN Orders o ON oi.OrderId=o.Id JOIN Customers c ON o.CustomerId=c.Id JOIN Products p ON oi.ProductId=p.Id" + (string.IsNullOrWhiteSpace(s) ? "" : " WHERE o.OrderNo LIKE @s OR c.CustomerName LIKE @s OR p.ProductCode LIKE @s OR p.ProductName LIKE @s OR oi.Description LIKE @s") + " ORDER BY o.Id DESC, oi.Id ASC";
    static string SupplierItemsSql(string s) => "SELECT si.Id,s.SupplierCode,s.SupplierName,p.ProductCode,p.ProductName,si.ItemType,si.SupplyDescription,si.DefaultUnitCost,si.Status,si.SupplierId,si.ProductId FROM SupplierItems si JOIN Suppliers s ON si.SupplierId=s.Id LEFT JOIN Products p ON si.ProductId=p.Id" + (string.IsNullOrWhiteSpace(s) ? "" : " WHERE s.SupplierName LIKE @s OR p.ProductName LIKE @s OR si.ItemType LIKE @s OR si.SupplyDescription LIKE @s") + " ORDER BY si.Id DESC";
    static string PurchaseOrdersSql(string s) => "SELECT po.Id,po.PONo,s.SupplierName,CONCAT(si.ItemType,' - ',si.SupplyDescription) SupplierItem,o.OrderNo RelatedOrderNo,po.Item,po.Quantity,po.UnitCost,(po.Quantity*po.UnitCost) EstimatedTotal,po.Status,po.OrderDate,po.ExpectedDate,po.SupplierId,po.SupplierItemId,po.RelatedOrderId FROM PurchaseOrders po JOIN Suppliers s ON po.SupplierId=s.Id LEFT JOIN SupplierItems si ON po.SupplierItemId=si.Id LEFT JOIN Orders o ON po.RelatedOrderId=o.Id" + (string.IsNullOrWhiteSpace(s) ? "" : " WHERE po.PONo LIKE @s OR s.SupplierName LIKE @s OR si.SupplyDescription LIKE @s OR o.OrderNo LIKE @s OR po.Item LIKE @s OR po.Status LIKE @s") + " ORDER BY po.Id DESC";
    static string ComplaintsSql(string s) => "SELECT cp.Id,cp.ComplaintNo,c.CustomerName,o.OrderNo RelatedOrderNo,cp.IssueType,cp.Priority,cp.Status,u.Username AssignedUser,cp.CreatedDate,cp.Notes,cp.CustomerId,cp.RelatedOrderId,cp.AssignedUserId FROM Complaints cp JOIN Customers c ON cp.CustomerId=c.Id LEFT JOIN Orders o ON cp.RelatedOrderId=o.Id LEFT JOIN Users u ON cp.AssignedUserId=u.Id" + (string.IsNullOrWhiteSpace(s) ? "" : " WHERE cp.ComplaintNo LIKE @s OR c.CustomerName LIKE @s OR o.OrderNo LIKE @s OR cp.IssueType LIKE @s OR cp.Status LIKE @s") + " ORDER BY cp.Id DESC";
    static string StockSql(string s) => "SELECT st.Id,st.ItemCode,p.ProductCode,p.ProductName,st.ItemName,st.ItemType,st.Warehouse,st.Quantity,st.ReorderPoint,st.Status,st.LastUpdated,st.ProductId FROM Stock st LEFT JOIN Products p ON st.ProductId=p.Id" + (string.IsNullOrWhiteSpace(s) ? "" : " WHERE st.ItemCode LIKE @s OR p.ProductCode LIKE @s OR p.ProductName LIKE @s OR st.ItemName LIKE @s OR st.Warehouse LIKE @s OR st.Status LIKE @s") + " ORDER BY st.Id DESC";
    static string StockMovementsSql(string s) => "SELECT sm.Id,sm.MovementNo,st.ItemCode,st.ItemName,sm.MovementType,sm.Quantity,sm.Warehouse,sm.MovementDate,sm.Reason,sm.StockId FROM StockMovements sm JOIN Stock st ON sm.StockId=st.Id" + (string.IsNullOrWhiteSpace(s) ? "" : " WHERE sm.MovementNo LIKE @s OR st.ItemCode LIKE @s OR st.ItemName LIKE @s OR sm.MovementType LIKE @s OR sm.Warehouse LIKE @s OR sm.Reason LIKE @s") + " ORDER BY sm.Id DESC";
    static string ReplySlipsSql(string s) => "SELECT rs.Id,rs.ReplySlipNo,d.DeliveryNoteNo,c.CustomerName,rs.ContactPerson,rs.ResponseType,rs.SatisfactionRating,rs.FollowUpRequired,rs.ReceivedBy,rs.SignatureRef,rs.Status,rs.ReturnedDate,rs.Remarks,rs.DeliveryNoteId,rs.CustomerId FROM ReplySlips rs JOIN DeliveryNotes d ON rs.DeliveryNoteId=d.Id LEFT JOIN Customers c ON rs.CustomerId=c.Id" + (string.IsNullOrWhiteSpace(s) ? "" : " WHERE rs.ReplySlipNo LIKE @s OR d.DeliveryNoteNo LIKE @s OR c.CustomerName LIKE @s OR rs.SignatureRef LIKE @s") + " ORDER BY rs.Id DESC";
    public static DataTable GetRelationships() => Sql("SELECT TABLE_NAME ChildTable,COLUMN_NAME ChildColumn,REFERENCED_TABLE_NAME ParentTable,REFERENCED_COLUMN_NAME ParentColumn,CONSTRAINT_NAME ConstraintName FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE WHERE TABLE_SCHEMA=DATABASE() AND REFERENCED_TABLE_NAME IS NOT NULL ORDER BY TABLE_NAME,COLUMN_NAME");
    public static List<LookupItem> GetLookup(string table) { string label = table switch { "UserRoles" => "RoleName", "Users" => "Username", "Customers" => "CustomerName", "Suppliers" => "SupplierName", "SupplierItems" => "SupplyDescription", "Products" => "ProductName", "Orders" => "OrderNo", "Stock" => "ItemName", "DeliveryNotes" => "DeliveryNoteNo", "Invoices" => "InvoiceNo", "ReplySlips" => "ReplySlipNo", _ => "Id" }; var list = new List<LookupItem>(); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = $"SELECT Id,`{label}` FROM `{table}` ORDER BY Id"; using var r = cmd.ExecuteReader(); while (r.Read()) list.Add(new LookupItem(Convert.ToInt32(r[0]), $"{r[0]} - {r[1]}")); return list; }
    public static List<LookupItem> GetSupplierItemsForSupplier(int supplierId) { var list = new List<LookupItem>(); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = "SELECT si.Id,CONCAT(si.ItemType,' - ',si.SupplyDescription,CASE WHEN p.ProductCode IS NULL THEN '' ELSE CONCAT(' (',p.ProductCode,' ',p.ProductName,')') END) FROM SupplierItems si LEFT JOIN Products p ON si.ProductId=p.Id WHERE si.SupplierId=@supplierId AND si.Status='Active' ORDER BY si.ItemType,si.SupplyDescription"; cmd.Parameters.AddWithValue("@supplierId", supplierId); using var r = cmd.ExecuteReader(); while (r.Read()) list.Add(new LookupItem(Convert.ToInt32(r[0]), Convert.ToString(r[1]) ?? "")); return list; }
    public static decimal GetSupplierItemUnitCost(int id) { using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = "SELECT DefaultUnitCost FROM SupplierItems WHERE Id=@id"; cmd.Parameters.AddWithValue("@id", id); return decimal.TryParse(Convert.ToString(cmd.ExecuteScalar()), out var v) ? v : 0; }
    public static string GenerateNextCode(string table, string col, string prefix, string sep, int width) { int max = 0; using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = $"SELECT `{col}` FROM `{table}` WHERE `{col}` LIKE @p"; cmd.Parameters.AddWithValue("@p", prefix + sep + "%"); using var r = cmd.ExecuteReader(); string pat = "^" + Regex.Escape(prefix + sep) + @"(\d+)$"; while (r.Read()) { var m = Regex.Match(Convert.ToString(r[0]) ?? "", pat); if (m.Success && int.TryParse(m.Groups[1].Value, out int n) && n > max) max = n; } return prefix + sep + (max + 1).ToString("D" + width); }
    static object? Scalar(string sql, params MySqlParameter[] ps) { using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = sql; foreach (var p in ps) cmd.Parameters.Add(p); return cmd.ExecuteScalar(); }
    static int I(Dictionary<string, object?> v, string k) => v.TryGetValue(k, out var x) && int.TryParse(Convert.ToString(x), out int n) ? n : 0; static decimal D(Dictionary<string, object?> v, string k) => v.TryGetValue(k, out var x) && decimal.TryParse(Convert.ToString(x), out var n) ? n : 0;
    public static decimal GetProductUnitPrice(int id) => decimal.TryParse(Convert.ToString(Scalar("SELECT UnitPrice FROM Products WHERE Id=@id", new MySqlParameter("@id", id))), out var v) ? v : 0; public static string GetProductDisplayName(int id) => Convert.ToString(Scalar("SELECT ProductName FROM Products WHERE Id=@id", new MySqlParameter("@id", id))) ?? "";
    static void Prepare(string table, Dictionary<string, object?> v) { if (table == "Orders") { int p = I(v, "ProductId"), q = I(v, "Quantity"); if (p > 0 && q > 0) v["TotalAmount"] = GetProductUnitPrice(p) * q; } if (table == "OrderItems") { int p = I(v, "ProductId"), q = I(v, "Quantity"); decimal disc = D(v, "Discount"), unit = p > 0 ? GetProductUnitPrice(p) : D(v, "UnitPrice"); if (p > 0) { v["Description"] = GetProductDisplayName(p); v["UnitPrice"] = unit; } if (q > 0) v["LineTotal"] = Math.Max(0, unit * q - disc); } if (table == "PurchaseOrders") { int si = I(v, "SupplierItemId"); if (si > 0) { var desc = Convert.ToString(Scalar("SELECT SupplyDescription FROM SupplierItems WHERE Id=@id", new MySqlParameter("@id", si))) ?? ""; if (string.IsNullOrWhiteSpace(Convert.ToString(v.GetValueOrDefault("Item")))) v["Item"] = desc; if (D(v, "UnitCost") == 0) v["UnitCost"] = GetSupplierItemUnitCost(si); } } if (table == "Complaints") { int o = I(v, "RelatedOrderId"); if (o > 0) { int cid = Convert.ToInt32(Scalar("SELECT CustomerId FROM Orders WHERE Id=@id", new MySqlParameter("@id", o)) ?? 0); if (cid > 0) v["CustomerId"] = cid; } } if (table == "Stock") { int q = I(v, "Quantity"), r = I(v, "ReorderPoint"); v["Status"] = q <= r ? "LOW STOCK" : "Normal"; int p = I(v, "ProductId"); if (p > 0 && string.IsNullOrWhiteSpace(Convert.ToString(v.GetValueOrDefault("ItemName")))) v["ItemName"] = GetProductDisplayName(p); } if (table == "DeliveryNotes") { string wh = Convert.ToString(v.GetValueOrDefault("Warehouse")) ?? ""; if (string.IsNullOrWhiteSpace(Convert.ToString(v.GetValueOrDefault("FromAddress")))) v["FromAddress"] = wh switch { "WH-HK-01" => "Premium Living Furniture HK Warehouse, Kwun Tong, Hong Kong", "WH-CN-01" => "Premium Living Furniture China Warehouse, Guangdong", "WH-VN-01" => "Premium Living Furniture Vietnam Warehouse, Ho Chi Minh City", _ => wh }; int oid = I(v, "OrderId"); if (oid > 0 && string.IsNullOrWhiteSpace(Convert.ToString(v.GetValueOrDefault("ToAddress")))) v["ToAddress"] = Convert.ToString(Scalar("SELECT c.Address FROM Orders o JOIN Customers c ON o.CustomerId=c.Id WHERE o.Id=@id", new MySqlParameter("@id", oid))) ?? ""; if (string.IsNullOrWhiteSpace(Convert.ToString(v.GetValueOrDefault("RouteNotes")))) { string from = Convert.ToString(v.GetValueOrDefault("FromAddress")) ?? ""; string to = Convert.ToString(v.GetValueOrDefault("ToAddress")) ?? ""; v["RouteNotes"] = string.IsNullOrWhiteSpace(from + to) ? "" : from + " -> " + to; } } if (table == "ReplySlips") { int dn = I(v, "DeliveryNoteId"); if (dn > 0) { int cid = Convert.ToInt32(Scalar("SELECT o.CustomerId FROM DeliveryNotes d JOIN Orders o ON d.OrderId=o.Id WHERE d.Id=@id", new MySqlParameter("@id", dn)) ?? 0); if (cid > 0) v["CustomerId"] = cid; } } if (table == "Invoices") { int o = I(v, "OrderId"); if (o > 0) { int cid = Convert.ToInt32(Scalar("SELECT CustomerId FROM Orders WHERE Id=@id", new MySqlParameter("@id", o)) ?? 0); decimal amount = Convert.ToDecimal(Scalar("SELECT TotalAmount FROM Orders WHERE Id=@id", new MySqlParameter("@id", o)) ?? 0); if (cid > 0) v["CustomerId"] = cid; if (amount > 0) v["Amount"] = amount; } } }
    public static void AddRecord(string table, Dictionary<string, object?> values) { Prepare(table, values); var cols = Cols[table].Where(values.ContainsKey).ToArray(); using var c = GetConnection(); c.Open(); using var tx = c.BeginTransaction(); try { using var cmd = c.CreateCommand(); cmd.Transaction = tx; cmd.CommandText = $"INSERT INTO `{table}` ({string.Join(",", cols.Select(x => $"`{x}`"))}) VALUES ({string.Join(",", cols.Select(x => "@" + x))})"; foreach (var col in cols) cmd.Parameters.AddWithValue("@" + col, values[col] ?? DBNull.Value); cmd.ExecuteNonQuery(); if (table == "StockMovements") ApplyStockMovement(c, tx, values); if (table == "Payments") UpdateInvoiceStatus(c, tx, I(values, "InvoiceId")); tx.Commit(); } catch { tx.Rollback(); throw; } }
    static void ApplyStockMovement(MySqlConnection c, MySqlTransaction tx, Dictionary<string, object?> v) { int stockId = I(v, "StockId"), qty = I(v, "Quantity"); string type = Convert.ToString(v.GetValueOrDefault("MovementType")) ?? ""; int delta = type == "Receipt" ? qty : type == "Issue" ? -qty : type == "Adjustment" ? qty : 0; using var cmd = c.CreateCommand(); cmd.Transaction = tx; cmd.CommandText = "UPDATE Stock SET Quantity=GREATEST(0,Quantity+@d), Status=CASE WHEN GREATEST(0,Quantity+@d)<=ReorderPoint THEN 'LOW STOCK' ELSE 'Normal' END, LastUpdated=CURDATE() WHERE Id=@id"; cmd.Parameters.AddWithValue("@d", delta); cmd.Parameters.AddWithValue("@id", stockId); cmd.ExecuteNonQuery(); }
    static void UpdateInvoiceStatus(MySqlConnection c, MySqlTransaction tx, int id) { if (id <= 0) return; using var cmd = c.CreateCommand(); cmd.Transaction = tx; cmd.CommandText = "UPDATE Invoices i SET PaymentStatus=CASE WHEN (SELECT COALESCE(SUM(Amount),0) FROM Payments p WHERE p.InvoiceId=i.Id)>=i.Amount THEN 'Paid' WHEN (SELECT COALESCE(SUM(Amount),0) FROM Payments p WHERE p.InvoiceId=i.Id)>0 THEN 'Partially Paid' ELSE 'Unpaid' END WHERE i.Id=@id"; cmd.Parameters.AddWithValue("@id", id); cmd.ExecuteNonQuery(); }
    public static void AddSalesOrderWithItems(string no, int customer, string status, string date, string priority, int user, List<SalesOrderItemDraft> items) { if (items.Count == 0) throw new ArgumentException("At least one product must be selected."); using var c = GetConnection(); c.Open(); using var tx = c.BeginTransaction(); try { using var cmd = c.CreateCommand(); cmd.Transaction = tx; cmd.CommandText = "INSERT INTO Orders (OrderNo,CustomerId,ProductId,Quantity,Status,OrderDate,Priority,SalesUserId,TotalAmount) VALUES (@no,@c,@p,@q,@s,@d,@pr,@u,@t)"; cmd.Parameters.AddWithValue("@no", no); cmd.Parameters.AddWithValue("@c", customer); cmd.Parameters.AddWithValue("@p", items[0].ProductId); cmd.Parameters.AddWithValue("@q", items.Sum(x => x.Quantity)); cmd.Parameters.AddWithValue("@s", status); cmd.Parameters.AddWithValue("@d", date); cmd.Parameters.AddWithValue("@pr", priority); cmd.Parameters.AddWithValue("@u", user); cmd.Parameters.AddWithValue("@t", items.Sum(x => x.LineTotal)); cmd.ExecuteNonQuery(); long oid = cmd.LastInsertedId; foreach (var it in items) { using var ic = c.CreateCommand(); ic.Transaction = tx; ic.CommandText = "INSERT INTO OrderItems (OrderId,ProductId,Description,Quantity,UnitPrice,Discount,LineTotal) VALUES (@o,@p,@desc,@q,@u,@d,@l)"; ic.Parameters.AddWithValue("@o", oid); ic.Parameters.AddWithValue("@p", it.ProductId); ic.Parameters.AddWithValue("@desc", it.Description); ic.Parameters.AddWithValue("@q", it.Quantity); ic.Parameters.AddWithValue("@u", it.UnitPrice); ic.Parameters.AddWithValue("@d", it.Discount); ic.Parameters.AddWithValue("@l", it.LineTotal); ic.ExecuteNonQuery(); } tx.Commit(); } catch { tx.Rollback(); throw; } }

    public static void EnsureMaterialsTable() { using var c = GetConnection(); c.Open(); using (var cmd = c.CreateCommand()) { cmd.CommandText = @"CREATE TABLE IF NOT EXISTS Materials(Id INT AUTO_INCREMENT PRIMARY KEY,MaterialName VARCHAR(150) NOT NULL,PhysicalQuantity INT NOT NULL DEFAULT 0,Unit VARCHAR(50) NOT NULL,SupplierId INT NULL,ProductId INT NULL,INDEX IX_Materials_SupplierId(SupplierId),INDEX IX_Materials_ProductId(ProductId)) ENGINE=InnoDB"; cmd.ExecuteNonQuery(); } EnsureColumn(c, "Materials", "SupplierId", "ALTER TABLE Materials ADD COLUMN SupplierId INT NULL AFTER Unit"); EnsureColumn(c, "Materials", "ProductId", "ALTER TABLE Materials ADD COLUMN ProductId INT NULL AFTER SupplierId"); EnsureIndex(c, "Materials", "IX_Materials_SupplierId", "CREATE INDEX IX_Materials_SupplierId ON Materials(SupplierId)"); EnsureIndex(c, "Materials", "IX_Materials_ProductId", "CREATE INDEX IX_Materials_ProductId ON Materials(ProductId)"); EnsureForeignKey(c, "Materials", "FK_Materials_Suppliers", "ALTER TABLE Materials ADD CONSTRAINT FK_Materials_Suppliers FOREIGN KEY(SupplierId) REFERENCES Suppliers(Id)"); EnsureForeignKey(c, "Materials", "FK_Materials_Products", "ALTER TABLE Materials ADD CONSTRAINT FK_Materials_Products FOREIGN KEY(ProductId) REFERENCES Products(Id)"); SeedDefaultMaterialsIfEmpty(c); }
    static void EnsureColumn(MySqlConnection c, string table, string column, string ddl) { using var check = c.CreateCommand(); check.CommandText = "SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=@t AND COLUMN_NAME=@c"; check.Parameters.AddWithValue("@t", table); check.Parameters.AddWithValue("@c", column); if (Convert.ToInt32(check.ExecuteScalar() ?? 0) > 0) return; using var cmd = c.CreateCommand(); cmd.CommandText = ddl; cmd.ExecuteNonQuery(); }
    static void EnsureIndex(MySqlConnection c, string table, string indexName, string ddl) { using var check = c.CreateCommand(); check.CommandText = "SELECT COUNT(*) FROM INFORMATION_SCHEMA.STATISTICS WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=@t AND INDEX_NAME=@i"; check.Parameters.AddWithValue("@t", table); check.Parameters.AddWithValue("@i", indexName); if (Convert.ToInt32(check.ExecuteScalar() ?? 0) > 0) return; using var cmd = c.CreateCommand(); cmd.CommandText = ddl; cmd.ExecuteNonQuery(); }
    static void EnsureForeignKey(MySqlConnection c, string table, string fkName, string ddl) { using var check = c.CreateCommand(); check.CommandText = "SELECT COUNT(*) FROM INFORMATION_SCHEMA.TABLE_CONSTRAINTS WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=@t AND CONSTRAINT_NAME=@fk AND CONSTRAINT_TYPE='FOREIGN KEY'"; check.Parameters.AddWithValue("@t", table); check.Parameters.AddWithValue("@fk", fkName); if (Convert.ToInt32(check.ExecuteScalar() ?? 0) > 0) return; try { using var cmd = c.CreateCommand(); cmd.CommandText = ddl; cmd.ExecuteNonQuery(); } catch (MySqlException ex) when (ex.Number == 1215 || ex.Number == 1826 || ex.Number == 1061 || ex.Number == 1060) { } }
    static void SeedDefaultMaterialsIfEmpty(MySqlConnection c) { using (var count = c.CreateCommand()) { count.CommandText = "SELECT COUNT(*) FROM Materials"; if (Convert.ToInt32(count.ExecuteScalar() ?? 0) > 0) return; } using var cmd = c.CreateCommand(); cmd.CommandText = "INSERT INTO Materials(MaterialName,PhysicalQuantity,Unit,SupplierId,ProductId) VALUES(@m1,500,'pcs',1,2),(@m2,200,'meter',2,2),(@m3,100,'meter',3,1),(@m4,50,'block',3,1)"; cmd.Parameters.AddWithValue("@m1", "Oak Wood Plank"); cmd.Parameters.AddWithValue("@m2", "Steel Tube / Hardware Parts"); cmd.Parameters.AddWithValue("@m3", "Fabric Cloth"); cmd.Parameters.AddWithValue("@m4", "High Density Foam"); try { cmd.ExecuteNonQuery(); } catch (MySqlException) { using var fallback = c.CreateCommand(); fallback.CommandText = "INSERT INTO Materials(MaterialName,PhysicalQuantity,Unit) VALUES('Oak Wood Plank',500,'pcs'),('Steel Tube / Hardware Parts',200,'meter'),('Fabric Cloth',100,'meter'),('High Density Foam',50,'block')"; fallback.ExecuteNonQuery(); } }
    public static DataTable GetMaterials(string search = "") { EnsureMaterialsTable(); var dt = new DataTable(); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = "SELECT m.Id,m.MaterialName,m.PhysicalQuantity,m.Unit,s.SupplierCode,s.SupplierName,p.ProductCode,p.ProductName,m.SupplierId,m.ProductId FROM Materials m LEFT JOIN Suppliers s ON m.SupplierId=s.Id LEFT JOIN Products p ON m.ProductId=p.Id"; if (!string.IsNullOrWhiteSpace(search)) { cmd.CommandText += " WHERE m.MaterialName LIKE @s OR m.Unit LIKE @s OR s.SupplierCode LIKE @s OR s.SupplierName LIKE @s OR p.ProductCode LIKE @s OR p.ProductName LIKE @s"; cmd.Parameters.AddWithValue("@s", "%" + search.Trim() + "%"); } cmd.CommandText += " ORDER BY m.Id DESC"; using var r = cmd.ExecuteReader(); dt.Load(r); return dt; }
    public static void AddMaterial(string materialName, int physicalQuantity, string unit) { AddMaterial(materialName, physicalQuantity, unit, 0, 0); }
    public static void AddMaterial(string materialName, int physicalQuantity, string unit, int supplierId, int productId) { EnsureMaterialsTable(); if (string.IsNullOrWhiteSpace(materialName)) throw new ArgumentException("Material name is required."); if (string.IsNullOrWhiteSpace(unit)) throw new ArgumentException("Unit is required."); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = "INSERT INTO Materials(MaterialName,PhysicalQuantity,Unit,SupplierId,ProductId) VALUES(@name,@qty,@unit,@supplierId,@productId)"; cmd.Parameters.AddWithValue("@name", materialName.Trim()); cmd.Parameters.AddWithValue("@qty", Math.Max(0, physicalQuantity)); cmd.Parameters.AddWithValue("@unit", unit.Trim()); cmd.Parameters.AddWithValue("@supplierId", supplierId > 0 ? (object)supplierId : DBNull.Value); cmd.Parameters.AddWithValue("@productId", productId > 0 ? (object)productId : DBNull.Value); cmd.ExecuteNonQuery(); }
    public static void UpdateMaterial(int id, string materialName, int physicalQuantity, string unit, int supplierId, int productId) { EnsureMaterialsTable(); if (id <= 0) throw new ArgumentException("Invalid material id."); if (string.IsNullOrWhiteSpace(materialName)) throw new ArgumentException("Material name is required."); if (string.IsNullOrWhiteSpace(unit)) throw new ArgumentException("Unit is required."); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = "UPDATE Materials SET MaterialName=@name,PhysicalQuantity=@qty,Unit=@unit,SupplierId=@supplierId,ProductId=@productId WHERE Id=@id"; cmd.Parameters.AddWithValue("@id", id); cmd.Parameters.AddWithValue("@name", materialName.Trim()); cmd.Parameters.AddWithValue("@qty", Math.Max(0, physicalQuantity)); cmd.Parameters.AddWithValue("@unit", unit.Trim()); cmd.Parameters.AddWithValue("@supplierId", supplierId > 0 ? (object)supplierId : DBNull.Value); cmd.Parameters.AddWithValue("@productId", productId > 0 ? (object)productId : DBNull.Value); cmd.ExecuteNonQuery(); }
    public static void EnsureRawMaterialRequestsTable() { using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = @"CREATE TABLE IF NOT EXISTS RawMaterialRequests(Id INT AUTO_INCREMENT PRIMARY KEY,RequestNo VARCHAR(50) UNIQUE,StockId INT NULL,RequestedByUserId INT NULL,Quantity INT NOT NULL DEFAULT 1,RequiredDate DATE NULL,Priority VARCHAR(50),Status VARCHAR(50),Purpose VARCHAR(255),CreatedDate DATE,INDEX IX_RawMaterialRequests_StockId(StockId),INDEX IX_RawMaterialRequests_UserId(RequestedByUserId)) ENGINE=InnoDB"; cmd.ExecuteNonQuery(); try { EnsureForeignKey(c, "RawMaterialRequests", "FK_RawMaterialRequests_Stock", "ALTER TABLE RawMaterialRequests ADD CONSTRAINT FK_RawMaterialRequests_Stock FOREIGN KEY(StockId) REFERENCES Stock(Id)"); EnsureForeignKey(c, "RawMaterialRequests", "FK_RawMaterialRequests_User", "ALTER TABLE RawMaterialRequests ADD CONSTRAINT FK_RawMaterialRequests_User FOREIGN KEY(RequestedByUserId) REFERENCES Users(Id)"); } catch { } }
    public static DataTable RawRequests(string search = "") { EnsureRawMaterialRequestsTable(); var dt = new DataTable(); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = @"SELECT r.Id,r.RequestNo,st.ItemCode,st.ItemName,u.Username AS RequestedBy,r.Quantity,r.RequiredDate,r.Priority,r.Status,r.Purpose,r.CreatedDate,r.StockId,r.RequestedByUserId FROM RawMaterialRequests r LEFT JOIN Stock st ON r.StockId=st.Id LEFT JOIN Users u ON r.RequestedByUserId=u.Id"; if (!string.IsNullOrWhiteSpace(search)) { cmd.CommandText += @" WHERE r.RequestNo LIKE @s OR st.ItemCode LIKE @s OR st.ItemName LIKE @s OR u.Username LIKE @s OR r.Priority LIKE @s OR r.Status LIKE @s OR r.Purpose LIKE @s"; cmd.Parameters.AddWithValue("@s", "%" + search.Trim() + "%"); } cmd.CommandText += " ORDER BY r.Id DESC"; using var r = cmd.ExecuteReader(); dt.Load(r); return dt; }
    public static void AddRawRequest(string purpose, int quantity) { AddRawRequest(0, 0, quantity, DateTime.Today.AddDays(7).ToString("yyyy-MM-dd"), "Normal", "Submitted", purpose); }
    public static void AddRawRequest(int stockId, int requestedByUserId, int quantity, string requiredDate, string priority, string status, string purpose) { EnsureRawMaterialRequestsTable(); string requestNo = GenerateNextCode("RawMaterialRequests", "RequestNo", "RMR", "-", 4); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = @"INSERT INTO RawMaterialRequests(RequestNo,StockId,RequestedByUserId,Quantity,RequiredDate,Priority,Status,Purpose,CreatedDate) VALUES(@no,@stock,@user,@qty,@required,@priority,@status,@purpose,@created)"; cmd.Parameters.AddWithValue("@no", requestNo); cmd.Parameters.AddWithValue("@stock", stockId > 0 ? (object)stockId : DBNull.Value); cmd.Parameters.AddWithValue("@user", requestedByUserId > 0 ? (object)requestedByUserId : DBNull.Value); cmd.Parameters.AddWithValue("@qty", Math.Max(1, quantity)); cmd.Parameters.AddWithValue("@required", string.IsNullOrWhiteSpace(requiredDate) ? DBNull.Value : requiredDate); cmd.Parameters.AddWithValue("@priority", priority); cmd.Parameters.AddWithValue("@status", status); cmd.Parameters.AddWithValue("@purpose", string.IsNullOrWhiteSpace(purpose) ? "Production raw material request" : purpose.Trim()); cmd.Parameters.AddWithValue("@created", DateTime.Today.ToString("yyyy-MM-dd")); cmd.ExecuteNonQuery(); }
    public static void UpdateRawRequest(int id, int stockId, int requestedByUserId, int quantity, string requiredDate, string priority, string status, string purpose) { EnsureRawMaterialRequestsTable(); using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = @"UPDATE RawMaterialRequests SET StockId=@stock,RequestedByUserId=@user,Quantity=@qty,RequiredDate=@required,Priority=@priority,Status=@status,Purpose=@purpose WHERE Id=@id"; cmd.Parameters.AddWithValue("@id", id); cmd.Parameters.AddWithValue("@stock", stockId > 0 ? (object)stockId : DBNull.Value); cmd.Parameters.AddWithValue("@user", requestedByUserId > 0 ? (object)requestedByUserId : DBNull.Value); cmd.Parameters.AddWithValue("@qty", Math.Max(1, quantity)); cmd.Parameters.AddWithValue("@required", string.IsNullOrWhiteSpace(requiredDate) ? DBNull.Value : requiredDate); cmd.Parameters.AddWithValue("@priority", priority); cmd.Parameters.AddWithValue("@status", status); cmd.Parameters.AddWithValue("@purpose", string.IsNullOrWhiteSpace(purpose) ? "Production raw material request" : purpose.Trim()); cmd.ExecuteNonQuery(); }

    public static void DeleteRecord(string table, int id) { using var c = GetConnection(); c.Open(); using var cmd = c.CreateCommand(); cmd.CommandText = $"DELETE FROM `{table}` WHERE Id=@id"; cmd.Parameters.AddWithValue("@id", id); cmd.ExecuteNonQuery(); }
